# torch_ios: `safetensors.torch` shim.
#
# The two functions transformers imports at module load (pytorch_utils.py):
#   storage_ptr(tensor) -> int    # pointer to the underlying storage buffer
#   storage_size(tensor) -> int   # total bytes of the storage
#
# Pulled directly from safetensors/bindings/python/py_src/safetensors/torch.py
# (MIT licensed, by HuggingFace). Keeping them real — they're pure-python and
# transformers uses them in tensor-identity comparisons that must return sane
# results, otherwise tied-weights detection misfires.

import torch


def storage_ptr(tensor: torch.Tensor) -> int:
    try:
        return tensor.untyped_storage().data_ptr()
    except Exception:
        # Fall through for older torch or odd tensor types.
        try:
            return tensor.storage().data_ptr()
        except NotImplementedError:
            # meta / fake tensors have no real storage.
            return 0


def storage_size(tensor: torch.Tensor) -> int:
    try:
        return tensor.untyped_storage().nbytes()
    except AttributeError:
        # older torch: storage().size() returns element count, not bytes.
        try:
            return tensor.storage().size() * tensor.element_size()
        except NotImplementedError:
            return 0


# Real reading API — delegates to the pure-Python format reader in the
# parent module. transformers.from_pretrained calls `safe_open` from
# `safetensors` AND `load_file` from `safetensors.torch`, depending on
# code path. Both must work.
from safetensors import load_file as load_file   # noqa: F401
from safetensors import safe_open as _safe_open


def load(data: bytes) -> dict:
    """Decode an in-memory bytes buffer holding the .safetensors blob.
    Used by some HF loaders that mmap themselves and pass bytes."""
    import io, tempfile, os as _os
    # The header parser reads from a file — write to tmp and load.
    with tempfile.NamedTemporaryFile(delete=False, suffix=".safetensors") as f:
        f.write(data); path = f.name
    try:
        return load_file(path)
    finally:
        try: _os.remove(path)
        except OSError: pass


def _save_unsupported(*_a, **_k):
    raise NotImplementedError(
        "safetensors.torch.save_file: writing not implemented in the iOS shim. "
        "Use torch.save() instead, or convert on a Mac.")


save_file = _save_unsupported
save = _save_unsupported


__all__ = [
    "storage_ptr",
    "storage_size",
    "load_file",
    "save_file",
    "load",
    "save",
]
